#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

bool feasible(long long *a, int n, int k, long long x) {
    long long cur = 0;
    int cnt = 0;
    for (int i = 0; i < n; ++i) {
        cur += a[i];
        if (cur >= x) {
            ++cnt;
            cur = 0;
        }
    }
    return cnt >= k;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int n, k; scanf("%d %d", &n, &k);
        long long *a = (long long*)malloc(n * sizeof(long long));
        for (int i = 0; i < n; ++i) scanf("%lld", &a[i]);
        long long lo = -100000000000000LL, hi = 100000000000000LL;
        while (lo < hi) {
            long long mid = lo + (hi - lo + 1) / 2;
            if (feasible(a, n, k, mid)) lo = mid; else hi = mid - 1;
        }
        printf("%lld\n", lo);
        free(a);
    }
    return 0;
}

