import java.io.*;
import java.util.*;

public class Main {
    static boolean feasible(long[] a, int k, long x) {
        long cur = 0;
        int cnt = 0;
        for (long v : a) {
            cur += v;
            if (cur >= x) {
                cnt++;
                cur = 0;
            }
        }
        return cnt >= k;
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int n = fs.nextInt();
            int k = fs.nextInt();
            long[] a = new long[n];
            for (int i = 0; i < n; ++i) a[i] = fs.nextLong();
            long lo = -100000000000000L, hi = 100000000000000L;
            while (lo < hi) {
                long mid = lo + (hi - lo + 1) / 2;
                if (feasible(a, k, mid)) lo = mid; else hi = mid - 1;
            }
            sb.append(lo).append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

