import sys

def feasible(arr, k, x):
    cur = 0
    cnt = 0
    for v in arr:
        cur += v
        if cur >= x:
            cnt += 1
            cur = 0
    return cnt >= k

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it)); k = int(next(it))
        arr = [int(next(it)) for _ in range(n)]
        lo, hi = -10**14, 10**14
        while lo < hi:
            mid = lo + (hi - lo + 1)//2
            if feasible(arr, k, mid):
                lo = mid
            else:
                hi = mid - 1
        out_lines.append(str(lo))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

